## Error: Cannot read property 'map' of undefined

### Cause
Trying to call .map() on a variable that is undefined or null.

### Solution
```tsx
// Bad
{items.map(item => <Item key={item.id} {...item} />)}

// Good - Optional chaining
{items?.map(item => <Item key={item.id} {...item} />)}

// Good - Default empty array
{(items || []).map(item => <Item key={item.id} {...item} />)}

// Good - Check before render
{items && items.length > 0 && (
  items.map(item => <Item key={item.id} {...item} />)
)}

// Good - Initialize state properly
const [items, setItems] = useState<Item[]>([]);
```

## Error: Objects are not valid as a React child

### Cause
Trying to render an object directly instead of its properties.

### Solution
```tsx
// Bad
const user = { name: 'John', age: 30 };
return <div>{user}</div>;

// Good - Render specific properties
return <div>{user.name}</div>;

// Good - JSON stringify for debugging
return <pre>{JSON.stringify(user, null, 2)}</pre>;

// Good - Map object entries
return (
  <ul>
    {Object.entries(user).map(([key, value]) => (
      <li key={key}>{key}: {String(value)}</li>
    ))}
  </ul>
);
```

## Error: Too many re-renders. React limits the number of renders

### Cause
Calling setState directly in the component body or in useEffect without proper dependencies.

### Solution
```tsx
// Bad - Infinite loop
function Component() {
  const [count, setCount] = useState(0);
  setCount(count + 1); // Called on every render!
  return <div>{count}</div>;
}

// Good - Use useEffect with dependencies
function Component() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    setCount(prev => prev + 1);
  }, []); // Empty deps = run once

  return <div>{count}</div>;
}

// Bad - onClick with immediate call
<button onClick={handleClick()}>Click</button>

// Good - Pass function reference
<button onClick={handleClick}>Click</button>
<button onClick={() => handleClick(id)}>Click</button>
```

## Error: Hydration mismatch (Next.js/SSR)

### Cause
Server-rendered HTML doesn't match client-side rendered HTML.

### Solutions
```tsx
// 1. Use useEffect for client-only code
function Component() {
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) return null; // or skeleton

  return <div>{window.innerWidth}</div>;
}

// 2. Use dynamic import with ssr: false
import dynamic from 'next/dynamic';

const ClientOnlyComponent = dynamic(
  () => import('./ClientComponent'),
  { ssr: false }
);

// 3. Avoid Date/random in initial render
// Bad
const date = new Date().toLocaleString();

// Good
const [date, setDate] = useState<string>();
useEffect(() => {
  setDate(new Date().toLocaleString());
}, []);

// 4. Suppress hydration warning (last resort)
<div suppressHydrationWarning>{clientOnlyContent}</div>
```
